from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path not provided; cannot check mailbox.json."}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found in external services path."}

    try:
        with open(mailbox_path, 'r', encoding='utf-8') as f:
            mailbox_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse mailbox.json: {e}"}

    emails = []
    if isinstance(mailbox_data, list):
        emails = mailbox_data
    elif isinstance(mailbox_data, dict):
        if "emails" in mailbox_data:
            emails = mailbox_data["emails"]
        elif "sent" in mailbox_data:
            emails = mailbox_data["sent"]
        else:
            for key, val in mailbox_data.items():
                if isinstance(val, list) and len(val) > 0:
                    emails = val
                    break

    if not emails:
        return {"pass": False, "score": 0.0, "feedback": "No emails found in mailbox.json."}

    def normalize_dashes(s):
        s = str(s)
        s = s.replace('\u2013', '\u2014')
        s = s.replace(' -- ', ' \u2014 ')
        s = s.replace('--', '\u2014')
        s = s.replace(' - ', ' \u2014 ')
        return s

    def normalize(s):
        s = normalize_dashes(str(s))
        return re.sub(r'\s+', ' ', s).strip().lower()

    expected_subject = "Pattern Recurrence Alert: Dr. Sarah Chen \u2014 CO-16 \u2014 5 Instances"

    # Required content checks — all must be present in body
    required_claim_ids = [
        "CLM-2026-0234",
        "CLM-2026-0356",
        "CLM-2026-0489",
        "CLM-2026-0612",
        "CLM-2026-0892",
    ]
    required_phrases = [
        "Maria Santos",
        "Dr. Sarah Chen",
        "NPI: 1234567890",
        "CO-16",
        "N382",
        "Pattern Recurrence",
        "Operational",
    ]
    esc_pattern = re.compile(r'ESC-2026-00\d{2}')

    to_addr = "david.park@pathfinderbilling.com"
    from_addr = "maria.santos@pathfinderbilling.com"

    best_feedback = f"No email found to {to_addr}."
    best_score = 0.0

    for email in emails:
        if not isinstance(email, dict):
            continue

        # Check recipient
        e_to = None
        for field in ["to_addr", "to", "recipient", "to_address", "to_email", "recipients"]:
            if field in email and email[field]:
                e_to = email[field]
                break
        if e_to is None:
            continue
        e_to_str = " ".join(str(x) for x in e_to) if isinstance(e_to, list) else str(e_to)
        if to_addr not in e_to_str.lower():
            continue

        # Check sender (allow missing/unknown sender for sent-folder emails)
        e_from = ""
        for field in ["from_addr", "from", "sender", "from_address", "from_email"]:
            if field in email and email[field]:
                e_from = str(email[field]).strip().lower()
                break
        e_folder = str(email.get("folder", "")).strip().lower()
        if e_from and from_addr not in e_from and e_folder != "sent":
            continue

        # Check subject (collapse whitespace + normalize dashes, case-insensitive)
        e_subject = str(email.get("subject", ""))
        subject_ok = normalize(e_subject) == normalize(expected_subject)

        # Get body
        e_body = ""
        for field in ["body_text", "body", "content", "text", "message", "html", "body_html"]:
            if field in email and email[field]:
                e_body = str(email[field])
                break

        body_norm = normalize(e_body)

        # Check all required claim IDs
        missing_claims = [c for c in required_claim_ids if c.lower() not in body_norm]

        # Check all required phrases
        missing_phrases = [p for p in required_phrases if p.lower() not in body_norm]

        # Check ESC ID present
        esc_ok = bool(esc_pattern.search(e_body))

        all_claims_ok = len(missing_claims) == 0
        all_phrases_ok = len(missing_phrases) == 0

        if subject_ok and all_claims_ok and all_phrases_ok and esc_ok:
            return {"pass": True, "score": 1.0, "feedback": "Found matching Pattern Recurrence email to david.park with correct subject and all required content."}

        # Partial scoring for feedback
        total_checks = len(required_claim_ids) + len(required_phrases) + 2  # +subject, +esc
        passed_checks = (
            (1 if subject_ok else 0)
            + (len(required_claim_ids) - len(missing_claims))
            + (len(required_phrases) - len(missing_phrases))
            + (1 if esc_ok else 0)
        )
        score = 0.1 + 0.9 * (passed_checks / total_checks)

        issues = []
        if not subject_ok:
            issues.append(f"wrong subject (got: '{e_subject[:80]}')")
        if missing_claims:
            issues.append(f"missing claim IDs: {missing_claims}")
        if missing_phrases:
            issues.append(f"missing phrases: {missing_phrases}")
        if not esc_ok:
            issues.append("no ESC-2026-00XX ID found in body")

        feedback = f"Email to david.park found but failed checks — {'; '.join(issues)}."

        if score > best_score:
            best_score = score
            best_feedback = feedback

    return {"pass": False, "score": best_score, "feedback": best_feedback}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # This rubric checks external services (mailbox.json)
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json."}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json not found at {mailbox_path}"}

    try:
        with open(mailbox_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse mailbox.json: {e}"}

    emails = data.get("emails", [])
    if not isinstance(emails, list):
        return {"pass": False, "score": 0.0, "feedback": "'emails' key is missing or not a list in mailbox.json."}

    sent_emails = [e for e in emails if isinstance(e, dict) and str(e.get("folder", "")).strip().lower() == "sent"]
    count = len(sent_emails)

    subjects = [e.get("subject", "(no subject)") for e in sent_emails]
    subjects_str = "; ".join(subjects)

    if count == 3:
        return {"pass": True, "score": 1.0, "feedback": f"Found exactly 3 sent emails as expected. Subjects: {subjects_str}"}
    else:
        return {"pass": False, "score": 0.0, "feedback": f"Expected exactly 3 sent emails, but found {count}. Sent email subjects: {subjects_str}"}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "PBC_Claim_Register.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File 'PBC_Claim_Register.xlsx' not found in workspace."}

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open 'PBC_Claim_Register.xlsx': {e}"}

    target = 40

    # Check all sheets for a table with exactly 40 rows
    results = []
    for sheet_name in wb.sheetnames:
        sws = wb[sheet_name]
        # Count rows that have at least one non-empty cell
        non_empty_rows = 0
        for row in sws.iter_rows(min_row=1, max_row=sws.max_row):
            if any(cell.value is not None for cell in row):
                non_empty_rows += 1
        max_row = sws.max_row
        results.append((sheet_name, non_empty_rows, max_row))

        if non_empty_rows == target:
            return {
                "pass": True,
                "score": 1.0,
                "feedback": f"PBC_Claim_Register.xlsx sheet '{sheet_name}' has exactly {non_empty_rows} non-empty rows (including header), which meets the requirement of exactly 40 total rows."
            }
        if max_row == target and non_empty_rows != target:
            # Also accept if max_row is exactly 40 (some cells might appear empty but row exists)
            if non_empty_rows == target:
                return {
                    "pass": True,
                    "score": 1.0,
                    "feedback": f"PBC_Claim_Register.xlsx sheet '{sheet_name}' has max_row={max_row} matching exactly 40 total rows."
                }

    # If no sheet matched exactly, provide detailed failure feedback
    details = "; ".join([f"Sheet '{s}': {nr} non-empty rows, max_row={mr}" for s, nr, mr in results])
    return {
        "pass": False,
        "score": 0.0,
        "feedback": f"PBC_Claim_Register.xlsx does not have exactly 40 total rows (including header) on any sheet. Found: {details}. Expected exactly 40 rows."
    }

from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "PBC_Claim_Register.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "File PBC_Claim_Register.xlsx not found in workspace."}

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open PBC_Claim_Register.xlsx: {e}"}

    ws = wb.active

    # Expected values in order. None means BLANK.
    expected = [
        "CLM-2026-0845",
        "PAT-1021",
        "Jennifer Walsh",
        "03/10/2026",
        "Dr. Sarah Chen",
        "1234567890",
        "1122334455",
        "BlueCross TX",
        "BCTX1",
        "99213",
        "J06.9",
        None,  # BLANK
        "1",
        None,  # BLANK
        "Paid - Full",
        "$180.00",
        "$142.00",
        "$38.00",
        "$0.00",
        "Reconciled",
        None,  # BLANK
        None,  # BLANK
        None,  # BLANK
    ]

    def normalize(val):
        if val is None:
            return None
        s = str(val).strip()
        if s == '' or s.lower() == 'none':
            return None
        return s

    def is_blank(val):
        return val is None or str(val).strip() == '' or str(val).strip().lower() == 'none'

    def parse_number(s):
        """Try to extract a numeric value from a string, stripping $ and commas."""
        if s is None:
            return None
        s = str(s).strip().replace('$', '').replace(',', '').strip()
        try:
            return float(s)
        except ValueError:
            return None

    def values_match(expected_val, actual_val):
        # If expected is blank
        if expected_val is None:
            return is_blank(actual_val)

        norm_actual = normalize(actual_val)
        if norm_actual is None:
            return False

        norm_expected = expected_val.strip()

        # Direct case-insensitive match
        if norm_actual.lower() == norm_expected.lower():
            return True

        # Strip $ for comparison
        if norm_actual.replace('$', '').strip().lower() == norm_expected.replace('$', '').strip().lower():
            return True

        # Try numeric comparison with tolerance
        exp_num = parse_number(norm_expected)
        act_num = parse_number(norm_actual)
        if exp_num is not None and act_num is not None:
            if exp_num == 0 and act_num == 0:
                return True
            if exp_num != 0 and abs(act_num - exp_num) / abs(exp_num) <= 0.05:
                return True
            if exp_num == 0 and abs(act_num) < 0.01:
                return True

        # Date flexibility: 03/10/2026 vs 2026-03-10 etc.
        if norm_expected == "03/10/2026":
            date_patterns = ["03/10/2026", "3/10/2026", "2026-03-10", "2026/03/10", "03-10-2026"]
            if norm_actual in date_patterns:
                return True
            # openpyxl might return a datetime
            import datetime
            if isinstance(actual_val, datetime.datetime) or isinstance(actual_val, datetime.date):
                try:
                    if actual_val.month == 3 and actual_val.day == 10 and actual_val.year == 2026:
                        return True
                except:
                    pass

        # "1" could also be stored as integer 1
        if norm_expected == "1" and norm_actual in ["1", "1.0"]:
            return True

        return False

    num_expected = len(expected)

    # Search all rows
    found = False
    best_match_count = 0
    best_row_num = None
    best_mismatches = []

    for row_idx, row in enumerate(ws.iter_rows(min_row=1, values_only=False), start=1):
        cells = [cell.value for cell in row]
        # We need to find the starting column. The row might have extra columns.
        # Try each possible starting position.
        for start_col in range(max(1, len(cells) - num_expected + 1)):
            subset = cells[start_col:start_col + num_expected]
            if len(subset) < num_expected:
                # Pad with None
                subset = subset + [None] * (num_expected - len(subset))

            match_count = 0
            mismatches = []
            for i, (exp_v, act_v) in enumerate(zip(expected, subset)):
                if values_match(exp_v, act_v):
                    match_count += 1
                else:
                    mismatches.append((i, exp_v, normalize(act_v)))

            if match_count > best_match_count:
                best_match_count = match_count
                best_row_num = row_idx
                best_mismatches = mismatches

            if match_count == num_expected:
                found = True
                break
        if found:
            break

    if found:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"Found matching row at row {best_row_num} in PBC_Claim_Register.xlsx with all {num_expected} expected values."
        }
    else:
        detail = ""
        if best_row_num:
            detail = f" Best partial match at row {best_row_num} with {best_match_count}/{num_expected} matches. Mismatches: "
            for idx, exp, act in best_mismatches[:5]:
                detail += f"[col {idx}: expected={exp!r}, actual={act!r}] "
            if len(best_mismatches) > 5:
                detail += f"... and {len(best_mismatches)-5} more."
        return {
            "pass": False,
            "score": best_match_count / num_expected if num_expected > 0 else 0.0,
            "feedback": f"No row in PBC_Claim_Register.xlsx fully matches the expected values.{detail}"
        }

from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    fp = Path(workspace_path) / "PBC_Claim_Register.xlsx"
    if not fp.exists():
        return {"pass": False, "score": 0.0, "feedback": "File PBC_Claim_Register.xlsx not found."}

    wb = openpyxl.load_workbook(fp, data_only=True)
    ws = wb.active

    # Expected values for a row (columns A through W = 23 columns)
    expected = [
        "CLM-2026-0878",  # A
        "PAT-1035",       # B
        "David Kim",      # C
        "03/12/2026",     # D
        "Dr. James Miller",# E
        "2345678901",     # F
        None,              # G - BLANK
        "BlueCross TX",   # H
        "BCTX1",          # I
        "99214",          # J
        "M54.5",          # K
        None,              # L - BLANK
        "1",              # M
        None,              # N - BLANK
        "Paid - Full",    # O
        "$285.00",        # P
        "$228.00",        # Q
        "$57.00",         # R
        "$0.00",          # S
        "Reconciled",     # T
        None,              # U - BLANK
        None,              # V - BLANK
        None,              # W - BLANK
    ]

    def normalize(val):
        if val is None:
            return None
        s = str(val).strip()
        if s == '' or s.lower() == 'none':
            return None
        return s

    def money_val(s):
        """Extract numeric value from money string like $285.00"""
        if s is None:
            return None
        cleaned = re.sub(r'[^\d.\-]', '', str(s))
        try:
            return float(cleaned)
        except:
            return None

    def vals_match(actual, expected_val):
        a = normalize(actual)
        e = normalize(expected_val)
        # Both blank
        if a is None and e is None:
            return True
        # One blank, other not
        if a is None or e is None:
            return False
        # Direct case-insensitive match
        if a.lower() == e.lower():
            return True
        # Try numeric / money comparison with tolerance
        ma = money_val(a)
        me = money_val(e)
        if ma is not None and me is not None:
            if me == 0:
                return abs(ma) < 0.01
            return abs(ma - me) / max(abs(me), 0.001) <= 0.05
        # Date flexibility: 03/12/2026 vs 2026-03-12 etc.
        # Try removing leading zeros and comparing
        a_stripped = re.sub(r'\b0+(\d)', r'\1', a)
        e_stripped = re.sub(r'\b0+(\d)', r'\1', e)
        if a_stripped.lower() == e_stripped.lower():
            return True
        # Date: check if it's a datetime object rendered differently
        import datetime
        if isinstance(actual, datetime.datetime) or isinstance(actual, datetime.date):
            try:
                formatted = actual.strftime('%m/%d/%Y')
                if formatted == e:
                    return True
            except:
                pass
        return False

    # Search all rows
    found = False
    best_match_count = 0
    best_row_num = None
    best_mismatches = []

    for row in ws.iter_rows(min_row=1, max_row=ws.max_row):
        cells = [row[i].value if i < len(row) else None for i in range(23)]
        # Quick check: does column A match the claim ID?
        if normalize(cells[0]) is None:
            continue
        if normalize(cells[0]).upper() != "CLM-2026-0878":
            continue
        # Detailed check
        match_count = 0
        mismatches = []
        for idx in range(23):
            if vals_match(cells[idx] if idx < len(cells) else None, expected[idx]):
                match_count += 1
            else:
                mismatches.append((idx, normalize(cells[idx] if idx < len(cells) else None), normalize(expected[idx])))
        if match_count > best_match_count:
            best_match_count = match_count
            best_row_num = row[0].row
            best_mismatches = mismatches
        if match_count == 23:
            found = True
            break

    wb.close()

    if found:
        return {"pass": True, "score": 1.0, "feedback": f"Found matching row for CLM-2026-0878 with all 23 expected column values."}

    if best_row_num is not None:
        mismatch_details = "; ".join([f"Col {m[0]+1}: got '{m[1]}' expected '{m[2]}'" for m in best_mismatches])
        return {"pass": False, "score": best_match_count / 23.0, "feedback": f"Found row for CLM-2026-0878 at row {best_row_num} but {len(best_mismatches)} column(s) differ: {mismatch_details}"}

    return {"pass": False, "score": 0.0, "feedback": "No row with Claim ID 'CLM-2026-0878' found in PBC_Claim_Register.xlsx."}

from pathlib import Path
import openpyxl
import re
import datetime

def verify(workspace_path, external_services_path=None):
    # Search for the file using glob to be lenient
    target_files = list(Path(workspace_path).glob("**/PBC_Claim_Register.xlsx"))
    if not target_files:
        # Also try case-insensitive
        target_files = list(Path(workspace_path).glob("**/*.xlsx"))
        target_files = [f for f in target_files if 'claim_register' in f.name.lower()]
    if not target_files:
        return {"pass": False, "score": 0.0, "feedback": "File PBC_Claim_Register.xlsx not found in workspace."}

    target_file = target_files[0]

    try:
        wb = openpyxl.load_workbook(str(target_file), data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open {target_file.name}: {e}"}

    # Expected values in order. None means BLANK.
    expected = [
        "CLM-2026-0892",
        "PAT-1042",
        "Michael Torres",
        "03/15/2026",
        "Dr. Sarah Chen",
        "1234567890",
        "1122334455",
        "BlueCross TX",
        "BCTX1",
        "99214",
        "E11.65",
        None,  # BLANK
        "1",
        None,  # BLANK
        "Resubmitted",  # "Submitted" also acceptable
        "$285.00",
        "$0.00",
        "$285.00",
        "$0.00",
        None,  # BLANK
        None,  # BLANK
        "CO-16",
        "N382"
    ]

    # Column index 14 (0-based) is the status column where "Submitted" is also acceptable
    status_col_idx = 14

    def normalize(val):
        """Normalize a cell value to a stripped string, or None if blank."""
        if val is None:
            return None
        s = str(val).strip()
        if s == '' or s.lower() == 'none':
            return None
        return s

    def values_match(actual, expected_val, col_idx=None):
        """Loosely compare an actual cell value against an expected value."""
        actual_n = normalize(actual)
        if expected_val is None:
            # Expect blank
            return actual_n is None
        if actual_n is None:
            return False
        exp_str = str(expected_val).strip()

        # Direct case-insensitive match
        if actual_n.lower() == exp_str.lower():
            return True

        # Special handling for status column: accept "Submitted" as well
        if col_idx == status_col_idx:
            if actual_n.lower() in ["resubmitted", "submitted"]:
                return True

        # Try removing $ and commas for currency comparison
        def strip_currency(s):
            return s.replace('$', '').replace(',', '').strip()
        act_clean = strip_currency(actual_n)
        exp_clean = strip_currency(exp_str)
        if act_clean == exp_clean:
            return True

        # Try numeric comparison with tolerance
        try:
            act_num = float(act_clean)
            exp_num = float(exp_clean)
            if exp_num == 0:
                return abs(act_num) < 0.01
            if abs(act_num - exp_num) / max(abs(exp_num), 1e-9) < 0.05:
                return True
        except (ValueError, TypeError):
            pass

        # Date flexibility: 03/15/2026 vs 2026-03-15 etc.
        date_formats = ['%m/%d/%Y', '%Y-%m-%d', '%m-%d-%Y', '%d/%m/%Y', '%Y/%m/%d']
        exp_date = None
        act_date = None
        for fmt in date_formats:
            try:
                exp_date = datetime.datetime.strptime(exp_str, fmt).date()
                break
            except ValueError:
                continue
        if exp_date:
            for fmt in date_formats:
                try:
                    act_date = datetime.datetime.strptime(actual_n, fmt).date()
                    break
                except ValueError:
                    continue
            if act_date is None and isinstance(actual, datetime.datetime):
                act_date = actual.date()
            if act_date is None and isinstance(actual, datetime.date):
                act_date = actual
            if act_date is not None and act_date == exp_date:
                return True

        # Check if expected is "1" and actual could be 1 or 1.0
        if exp_str == "1":
            try:
                if float(actual_n) == 1.0:
                    return True
            except (ValueError, TypeError):
                pass

        return False

    num_expected = len(expected)
    best_match_count = 0
    best_row_idx = None
    best_mismatches = []

    # Check all sheets
    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]
        for row in ws.iter_rows(min_row=1, max_row=ws.max_row):
            cells = [cell.value for cell in row]
            if len(cells) < num_expected:
                continue
            for offset in range(len(cells) - num_expected + 1):
                match_count = 0
                mismatches = []
                for i in range(num_expected):
                    if values_match(cells[offset + i], expected[i], col_idx=i):
                        match_count += 1
                    else:
                        mismatches.append((i, expected[i], normalize(cells[offset + i])))
                if match_count > best_match_count:
                    best_match_count = match_count
                    best_row_idx = row[0].row
                    best_mismatches = mismatches
                if match_count == num_expected:
                    wb.close()
                    return {"pass": True, "score": 1.0, "feedback": f"Found matching row at row {row[0].row} in sheet '{sheet_name}' of {target_file.name} with all {num_expected} expected values."}

    wb.close()
    if best_row_idx is not None:
