    def expected_display(expected):
        if isinstance(expected, list):
            return " or ".join([repr(e) for e in expected])
        return repr(expected)

    best_match_count = 0
    best_row_idx = None
    best_mismatches = []
    total = len(expected_values)

    # Iterate through all rows in all sheets
    for sheet in wb.sheetnames:
        ws = wb[sheet]
        for row_idx, row in enumerate(ws.iter_rows(min_row=1, values_only=True), start=1):
            row_list = list(row)
            # Extend row if shorter than expected
            while len(row_list) < total:
                row_list.append(None)

            match_count = 0
            mismatches = []
            for col_idx, exp in enumerate(expected_values):
                actual_val = row_list[col_idx] if col_idx < len(row_list) else None
                if values_match(exp, actual_val):
                    match_count += 1
                else:
                    mismatches.append((col_idx + 1, expected_display(exp), normalize(actual_val)))

            if match_count > best_match_count:
                best_match_count = match_count
                best_row_idx = row_idx
                best_mismatches = mismatches

            if match_count == total:
                wb.close()
                return {"pass": True, "score": 1.0, "feedback": f"Found matching row at row {row_idx} in sheet '{sheet}' with all {total} expected values."}

    wb.close()

    # Allow 1-2 minor mismatches to still pass with reduced score
    if best_match_count >= total - 2 and best_match_count >= total * 0.9:
        mismatch_details = "; ".join([f"Col {c}: expected {e} got '{a}'" for c, e, a in best_mismatches])
        return {"pass": True, "score": best_match_count / total, "feedback": f"Best match at row {best_row_idx}: {best_match_count}/{total} values match. Minor mismatches: {mismatch_details}"}

    if best_row_idx:
        mismatch_details = "; ".join([f"Col {c}: expected {e} got '{a}'" for c, e, a in best_mismatches[:10]])
        return {"pass": False, "score": best_match_count / total, "feedback": f"No exact matching row found. Best match at row {best_row_idx} with {best_match_count}/{total} values matching. Mismatches: {mismatch_details}"}
    else:
        return {"pass": False, "score": 0.0, "feedback": "No rows found in PBC_Claim_Register.xlsx that match the expected values."}

from pathlib import Path
import openpyxl
import re
import datetime

def verify(workspace_path, external_services_path=None):
    # Search for the file using glob to be lenient
    file_path = None
    for f in Path(workspace_path).glob("**/*Claim_Register*"):
        if f.suffix == '.xlsx':
            file_path = f
            break
    if file_path is None:
        file_path = Path(workspace_path) / "PBC_Claim_Register.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: {file_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open workbook: {e}"}

    # Acceptable claim IDs for the first column per the rubric
    acceptable_claim_ids = ["CLM-2026-1107", "CLM-2026-1106"]

    expected = [
        None,  # placeholder for claim ID - checked separately
        "PAT-1058",
        "Linda Park",
        "03/20/2026",
        "Dr. James Miller",
        "2345678901",
        None,  # BLANK
        "BlueCross TX",
        "BCTX1",
        "29876",
        "M65.862",
        "LT",
        "7",
        "CLM-2026-1105",
        "Submitted",
        "$1,850.00",
        "$0.00",
        "$0.00",
        "$0.00",
        None,  # BLANK
        None,  # BLANK
        None,  # BLANK
        None,  # BLANK
    ]

    def normalize(val):
        if val is None:
            return None
        s = str(val).strip()
        if s == '' or s.lower() == 'none':
            return None
        return s

    def parse_number(s):
        if s is None:
            return None
        s = str(s).strip()
        cleaned = re.sub(r'[\$,\s]', '', s)
        try:
            return float(cleaned)
        except ValueError:
            return None

    def values_match(expected_val, actual_val):
        e = normalize(expected_val)
        a = normalize(actual_val)

        if e is None and a is None:
            return True
        if e is None or a is None:
            return False

        if e.lower() == a.lower():
            return True

        # Try numeric comparison
        e_num = parse_number(e)
        a_num = parse_number(a)
        if e_num is not None and a_num is not None:
            if e_num == 0 and a_num == 0:
                return True
            if e_num != 0:
                if abs(e_num - a_num) / abs(e_num) <= 0.05:
                    return True
            elif a_num != 0:
                if abs(e_num - a_num) / abs(a_num) <= 0.05:
                    return True

        # Date comparison
        if '/' in e:
            try:
                expected_date = datetime.datetime.strptime(e, '%m/%d/%Y').date()
                if hasattr(actual_val, 'date'):
                    if actual_val.date() == expected_date:
                        return True
                elif hasattr(actual_val, 'year'):
                    if actual_val == expected_date:
                        return True
                for fmt in ['%m/%d/%Y', '%Y-%m-%d', '%m-%d-%Y', '%d/%m/%Y']:
                    try:
                        if datetime.datetime.strptime(a, fmt).date() == expected_date:
                            return True
                    except ValueError:
                        pass
            except ValueError:
                pass

        # NPI / numeric string cleaning
        e_clean = re.sub(r'[^\w.]', '', e)
        a_clean = re.sub(r'[^\w.]', '', a)
        if e_clean.lower() == a_clean.lower():
            return True

        return False

    def is_acceptable_claim_id(val):
        n = normalize(val)
        if n is None:
            return False
        for cid in acceptable_claim_ids:
            if n.upper() == cid.upper():
                return True
        return False

    best_mismatches = None
    best_sheet = None
    best_claim_id = None

    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]
        for row in ws.iter_rows(min_row=1, max_row=ws.max_row):
            cells = [cell.value for cell in row]

            # Find a cell that matches one of the acceptable claim IDs
            start_idx = None
            matched_claim_id = None
            for i, c in enumerate(cells):
                if is_acceptable_claim_id(c):
                    start_idx = i
                    matched_claim_id = normalize(c)
                    break
            if start_idx is None:
                continue

            # Pad cells if needed
            if start_idx + len(expected) > len(cells):
                cells = cells + [None] * (start_idx + len(expected) - len(cells))

            all_match = True
            mismatches = []
            for j, exp_val in enumerate(expected):
                actual = cells[start_idx + j]
                if j == 0:
                    # Already verified claim ID
                    continue
                if not values_match(exp_val, actual):
                    all_match = False
                    mismatches.append(f"Column {j+1}: expected '{exp_val}', got '{actual}'")

            if all_match:
                return {"pass": True, "score": 1.0, "feedback": f"Found matching row with {matched_claim_id} in sheet '{sheet_name}' with all expected values."}
            else:
                if best_mismatches is None or len(mismatches) < len(best_mismatches):
                    best_mismatches = mismatches
                    best_sheet = sheet_name
                    best_claim_id = matched_claim_id

    if best_mismatches is not None:
        return {"pass": False, "score": 0.0, "feedback": f"Found row with {best_claim_id} in sheet '{best_sheet}' but mismatches: {'; '.join(best_mismatches)}"}

    return {"pass": False, "score": 0.0, "feedback": "No row containing an acceptable claim ID (CLM-2026-1107 or CLM-2026-1106) found in any sheet of PBC_Claim_Register.xlsx."}

from pathlib import Path
import openpyxl


def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "PBC_Claim_Register.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: {file_path}"}

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
        ws = wb.active

        rows = list(ws.iter_rows(min_row=1, values_only=True))
        if len(rows) < 2:
            return {"pass": True, "score": 1.0, "feedback": "File has 0 or 1 data rows, so no duplicates possible."}

        header = [str(c).strip().lower() if c is not None else "" for c in rows[0]]

        # Find Claim_ID column
        claim_id_col = None
        for i, h in enumerate(header):
            if h in ("claim_id", "claimid", "claim id"):
                claim_id_col = i
                break

        # Check for duplicate Claim_IDs
        duplicate_claim_ids = []
        if claim_id_col is not None:
            seen_ids = {}
            for row_idx, row in enumerate(rows[1:], start=2):
                val = row[claim_id_col]
                if val is None:
                    continue
                val_str = str(val).strip()
                if val_str == "":
                    continue
                if val_str in seen_ids:
                    duplicate_claim_ids.append((val_str, seen_ids[val_str], row_idx))
                else:
                    seen_ids[val_str] = row_idx
        else:
            return {"pass": False, "score": 0.0, "feedback": f"Could not find a 'Claim_ID' column in header: {header}"}

        # Check for fully duplicate rows
        def row_key(row):
            return tuple(str(c).strip() if c is not None else "" for c in row)

        seen_rows = {}
        duplicate_rows = []
        for row_idx, row in enumerate(rows[1:], start=2):
            rk = row_key(row)
            # Skip completely empty rows
            if all(v == "" for v in rk):
                continue
            if rk in seen_rows:
                duplicate_rows.append((row_idx, seen_rows[rk]))
            else:
                seen_rows[rk] = row_idx

        issues = []
        if duplicate_claim_ids:
            for cid, first_row, dup_row in duplicate_claim_ids:
                issues.append(f"Duplicate Claim_ID '{cid}' found in rows {first_row} and {dup_row}")
        if duplicate_rows:
            for dup_row, first_row in duplicate_rows:
                issues.append(f"Duplicate row found: rows {first_row} and {dup_row} are identical")

        if issues:
            return {
                "pass": False,
                "score": 0.0,
                "feedback": "Duplicates found in PBC_Claim_Register.xlsx: " + "; ".join(issues)
            }

        total_data_rows = sum(1 for row in rows[1:] if not all((str(c).strip() if c is not None else "") == "" for c in row))
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"No duplicate rows or Claim_IDs found in PBC_Claim_Register.xlsx. {total_data_rows} unique data rows checked."
        }

    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error reading PBC_Claim_Register.xlsx: {str(e)}"}

