from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    # Try to find the file with glob to be lenient
    workspace = Path(workspace_path)
    candidates = list(workspace.glob("**/PBC_Denial_Worklist*.xlsx"))
    if not candidates:
        candidates = list(workspace.glob("**/*.xlsx"))

    file_path = None
    for c in candidates:
        if "denial" in c.name.lower() or "worklist" in c.name.lower() or "pbc" in c.name.lower():
            file_path = c
            break
    if file_path is None and candidates:
        file_path = candidates[0]
    if file_path is None:
        file_path = workspace / "PBC_Denial_Worklist.xlsx"

    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found. Searched in {workspace}. No matching xlsx files found."}

    # The rubric says DEN-2026-0028 where 28 can be 29 or 30.
    # We'll also accept a broader range (28-31) to be lenient.
    # All other values are fixed.
    expected_values = [
        "DEN-2026-XXXX",  # special handling
        "CLM-2026-0892",
        "PAT-1042",
        "Michael Torres",
        "03/15/2026",
        "BlueCross TX",
        "CO-16",
        "N382",
        "Technical/Administrative",
        "Correct and Resubmit",
        "Resubmitted",
        "Maria Santos",
        "04/24/2026",
        None  # BLANK
    ]

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open workbook: {e}"}

    ws = wb.active

    def normalize(val):
        if val is None:
            return None
        s = str(val).strip()
        if s == '' or s.lower() == 'none':
            return None
        return s

    def is_blank(val):
        if val is None:
            return True
        s = str(val).strip()
        return s == '' or s.lower() == 'none'

    def den_id_matches(actual_val):
        """Check if actual matches DEN-2026-00XX where XX is 28-31 (lenient range)"""
        if actual_val is None:
            return False
        a = str(actual_val).strip().upper()
        # Accept DEN-2026-0028 through DEN-2026-0031
        pattern = r'^DEN-2026-00(2[89]|3[01])$'
        return bool(re.match(pattern, a))

    def values_match(actual, expected):
        if expected is None:
            return is_blank(actual)
        if actual is None:
            return False
        a = normalize(actual)
        e = normalize(expected)
        if a is None:
            return False
        # Case-insensitive comparison
        if a.lower() == e.lower():
            return True
        # Try date variants: strip leading zeros
        a_clean = re.sub(r'\b0+(\d)', r'\1', a)
        e_clean = re.sub(r'\b0+(\d)', r'\1', e)
        if a_clean.lower() == e_clean.lower():
            return True
        # Also handle date formats like 2026-03-15 vs 03/15/2026
        # Try converting common date patterns
        date_patterns = [
            (r'(\d{1,2})/(\d{1,2})/(\d{4})', lambda m: f"{int(m.group(1)):02d}/{int(m.group(2)):02d}/{m.group(3)}"),
            (r'(\d{4})-(\d{1,2})-(\d{1,2})', lambda m: f"{int(m.group(2)):02d}/{int(m.group(3)):02d}/{m.group(1)}"),
        ]
        def to_canonical_date(s):
            for pat, fn in date_patterns:
                m = re.match(pat, s.strip())
                if m:
                    return fn(m)
            return None

        a_date = to_canonical_date(a)
        e_date = to_canonical_date(e)
        if a_date and e_date and a_date == e_date:
            return True

        # Handle BCBS TX variants
        if e.lower() == "bluecross tx":
            variants = ["bluecross tx", "bcbs tx", "bcbstx", "blue cross tx", "bluecrosstx", "bcbs-tx"]
            if a.lower().replace(" ", "") in [v.replace(" ", "") for v in variants]:
                return True

        return False

    rows_to_check = list(range(1, ws.max_row + 1)) if ws.max_row and ws.max_row <= 50 else list(range(1, 51))
    # Prioritize rows 9-11 as stated in rubric, but check all rows for leniency
    priority_rows = [9, 10, 11]
    all_rows = priority_rows + [r for r in rows_to_check if r not in priority_rows]

    num_expected = len(expected_values)
    best_match_count = 0
    best_row = None
    best_mismatches = []

    for row_num in all_rows:
        row_cells = []
        for col in range(1, max(ws.max_column + 1 if ws.max_column else 1, 20)):
            row_cells.append(ws.cell(row=row_num, column=col).value)

        for start_col_idx in range(len(row_cells) - num_expected + 1):
            segment = row_cells[start_col_idx:start_col_idx + num_expected]
            match_count = 0
            mismatches = []
            for i, (act, exp) in enumerate(zip(segment, expected_values)):
                if i == 0:
                    # Special handling for DEN ID
                    if den_id_matches(act):
                        match_count += 1
                    else:
                        mismatches.append((i, "DEN-2026-00(28-31)", act))
                else:
                    if values_match(act, exp):
                        match_count += 1
                    else:
                        mismatches.append((i, exp, act))

            if match_count == num_expected:
                return {
                    "pass": True,
                    "score": 1.0,
                    "feedback": f"Row {row_num} contains all expected values starting at column {start_col_idx + 1}. DEN ID: {segment[0]}"
                }

            if match_count > best_match_count:
                best_match_count = match_count
                best_row = row_num
                best_mismatches = mismatches

    # Diagnostic info
    diag_lines = []
    for row_num in priority_rows:
        row_vals = []
        for col in range(1, min(ws.max_column + 1 if ws.max_column else 1, 20)):
            row_vals.append(repr(ws.cell(row=row_num, column=col).value))
        diag_lines.append(f"Row {row_num}: {row_vals}")

    mismatch_info = ""
    if best_row is not None:
        mismatch_info = f"\nBest partial match: Row {best_row} with {best_match_count}/{num_expected} matches. Mismatches: {best_mismatches}"

    return {
        "pass": False,
        "score": 0.0,
        "feedback": f"Expected values not found in PBC_Denial_Worklist.xlsx. Row contents (rows 9-11):\n" + "\n".join(diag_lines) + mismatch_info
    }

from pathlib import Path
import openpyxl
import re
import datetime

def verify(workspace_path, external_services_path=None):
    # Try to find the file with glob
    fp = None
    candidates = list(Path(workspace_path).glob("**/PBC_Denial_Worklist.xlsx"))
    if candidates:
        fp = candidates[0]
    else:
        fp = Path(workspace_path) / "PBC_Denial_Worklist.xlsx"

    if not fp.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: {fp}"}

    try:
        wb = openpyxl.load_workbook(fp, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open workbook: {e}"}

    ws = wb.active

    # The rubric says DEN-2026-0029 where 29 can be 28 or 30
    # So we accept DEN-2026-0028, DEN-2026-0029, DEN-2026-0030
    # We also accept variants like DEN-2026-0035 or other denial IDs with flexible matching
    expected_values = [
        "DEN-2026-FLEX",  # special handling
        "CLM-2026-1105",
        "PAT-1058",
        "Linda Park",
        "03/20/2026",
        "BlueCross TX",
        "CO-97",
        "N520",
        "Technical/Administrative",
        "Add Modifier and Resubmit",
        "Resubmitted",
        "Maria Santos",
        "04/24/2026",
        None  # BLANK
    ]

    def normalize(val):
        if val is None:
            return ""
        try:
            if isinstance(val, (datetime.datetime, datetime.date)):
                return val.strftime("%m/%d/%Y")
        except Exception:
            pass
        s = str(val).strip()
        return s

    def match_den_id(actual_str):
        """Match DEN-2026-0028, DEN-2026-0029, or DEN-2026-0030 (flexible)"""
        norm = actual_str.strip().upper()
        # Accept DEN-2026-0028, DEN-2026-0029, DEN-2026-0030
        if re.match(r'^DEN-2026-00(28|29|30)$', norm):
            return True
        # Also accept any DEN-2026-XXXX pattern as a looser fallback
        # But primary match is the three specific ones
        return False

    def match_date(actual_str, expected_str):
        """Flexible date matching"""
        date_pat = re.compile(r'^(\d{1,2})/(\d{1,2})/(\d{4})$')
        m_a = date_pat.match(actual_str)
        m_e = date_pat.match(expected_str)
        if m_a and m_e:
            return (int(m_a.group(1)) == int(m_e.group(1)) and
                    int(m_a.group(2)) == int(m_e.group(2)) and
                    m_a.group(3) == m_e.group(3))
        return False

    def match(actual, expected, idx):
        norm_actual = normalize(actual)

        # Special case: DEN ID (first column)
        if idx == 0:
            return match_den_id(norm_actual)

        # Special case: BLANK (last column)
        if expected is None:
            return norm_actual == "" or norm_actual.lower() == "none"

        norm_expected = str(expected).strip()

        # Case-insensitive comparison
        if norm_actual.lower() == norm_expected.lower():
            return True

        # Date matching
        if match_date(norm_actual, norm_expected):
            return True

        # Contains check as fallback for things like "BlueCross TX" vs "BCBS TX" etc.
        if norm_expected.lower() in norm_actual.lower() or norm_actual.lower() in norm_expected.lower():
            return True

        # Also try matching with flexible whitespace/case
        if re.sub(r'\s+', ' ', norm_actual.lower()) == re.sub(r'\s+', ' ', norm_expected.lower()):
            return True

        return False

    for row_num in [9, 10, 11]:
        row_cells = []
        for col in range(1, ws.max_column + 2):  # +2 for safety to check blank
            row_cells.append(ws.cell(row=row_num, column=col).value)

        # Try to match expected_values against consecutive columns starting from various offsets
        for start_col in range(min(5, len(row_cells))):
            all_match = True
            mismatches = []
            for i in range(len(expected_values)):
                col_idx = start_col + i
                if col_idx >= len(row_cells):
                    actual_val = None
                else:
                    actual_val = row_cells[col_idx]
                if not match(actual_val, expected_values[i], i):
                    all_match = False
                    mismatches.append((i, expected_values[i], normalize(actual_val)))
            if all_match:
                vals = [normalize(row_cells[start_col + i]) if (start_col + i) < len(row_cells) else "" for i in range(len(expected_values))]
                return {"pass": True, "score": 1.0, "feedback": f"Row {row_num} contains all expected values starting at column {start_col+1}. Values: {vals}"}

    # If no exact match, report best partial match
    best_row = None
    best_matched = 0
    best_mismatches = []
    best_start = 0
    for row_num in [9, 10, 11]:
        row_cells = []
        for col in range(1, ws.max_column + 2):
            row_cells.append(ws.cell(row=row_num, column=col).value)
        for start_col in range(min(5, len(row_cells))):
            matched = 0
            mismatches = []
            for i in range(len(expected_values)):
                col_idx = start_col + i
                actual_val = row_cells[col_idx] if col_idx < len(row_cells) else None
                if match(actual_val, expected_values[i], i):
                    matched += 1
                else:
