                break

    if file_path is None or not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: PBC_Denial_Worklist.xlsx in {workspace_path}"}

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
        ws = wb.active

        rows = []
        header_row = None
        denial_id_col = None

        for i, row in enumerate(ws.iter_rows(values_only=True)):
            # Skip completely empty rows
            if all(cell is None or str(cell).strip() == '' for cell in row):
                continue
            if header_row is None:
                header_row = tuple(str(c).strip() if c is not None else '' for c in row)
                # Find the Denial ID column (be flexible with naming)
                for col_idx, h in enumerate(header_row):
                    h_lower = h.lower().strip()
                    if 'denial' in h_lower and 'id' in h_lower:
                        denial_id_col = col_idx
                        break
                    elif h_lower in ('denialid', 'denial_id', 'denial id'):
                        denial_id_col = col_idx
                        break
                continue
            # Normalize cell values for comparison
            normalized = tuple(
                str(cell).strip().lower() if cell is not None else ''
                for cell in row
            )
            rows.append((i + 1, normalized, row))  # 1-indexed row number

        if not rows:
            return {"pass": True, "score": 1.0, "feedback": "PBC_Denial_Worklist.xlsx has no data rows (only header or empty), so no duplicates."}

        issues = []

        # Check for duplicate full rows
        seen_rows = {}
        duplicate_rows = []
        for row_num, normalized, raw in rows:
            if normalized in seen_rows:
                duplicate_rows.append((row_num, seen_rows[normalized]))
            else:
                seen_rows[normalized] = row_num

        if duplicate_rows:
            dup_details = "; ".join(
                f"Row {dup_row} is a duplicate of row {orig_row}"
                for dup_row, orig_row in duplicate_rows
            )
            issues.append(f"Found {len(duplicate_rows)} duplicate row(s): {dup_details}")

        # Check for duplicate Denial IDs
        if denial_id_col is not None:
            seen_ids = {}
            duplicate_ids = []
            for row_num, normalized, raw in rows:
                denial_id = normalized[denial_id_col] if denial_id_col < len(normalized) else ''
                if denial_id and denial_id in seen_ids:
                    duplicate_ids.append((row_num, denial_id, seen_ids[denial_id]))
                elif denial_id:
                    seen_ids[denial_id] = row_num

            if duplicate_ids:
                dup_id_details = "; ".join(
                    f"Row {dup_row} has Denial ID '{did}' which duplicates row {orig_row}"
                    for dup_row, did, orig_row in duplicate_ids
                )
                issues.append(f"Found {len(duplicate_ids)} duplicate Denial ID(s): {dup_id_details}")
        else:
            # If we can't find a Denial ID column, note it but don't fail on that alone
            pass

        if issues:
            return {
                "pass": False,
                "score": 0.0,
                "feedback": f"PBC_Denial_Worklist.xlsx has duplicates. " + " | ".join(issues)
            }

        denial_id_info = f" Denial ID column found at index {denial_id_col} ('{header_row[denial_id_col]}')." if denial_id_col is not None else " No Denial ID column detected (checked row uniqueness only)."
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"PBC_Denial_Worklist.xlsx contains {len(rows)} data rows with no duplicate rows or Denial IDs.{denial_id_info}"
        }
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error reading PBC_Denial_Worklist.xlsx: {str(e)}"}

