    valid_esc_ids = {"ESC-2026-0008", "ESC-2026-0009", "ESC-2026-0010"}

    def normalize(val):
        if val is None:
            return ""
        return str(val).strip()

    def check_row(row_num):
        row_vals = []
        for col in range(1, ws.max_column + 1):
            cell_val = ws.cell(row=row_num, column=col).value
            row_vals.append(cell_val)

