                    break
            if found_esc:
                break
        if found_esc:
            score += 1
            feedback_parts.append("Found valid ESC ID")
        else:
            feedback_parts.append(f"Missing ESC ID (expected one of {valid_esc_ids})")

        # Check date 04/24/2026 - be flexible with date formats
        found_date = False
        for idx, s in enumerate(row_strs):
