                if claim in s:
                    found_claims.add(claim)
        if found_claims == expected_claims:
            score += 1
            feedback_parts.append("Found all 5 claims")
        else:
            missing = expected_claims - found_claims
            feedback_parts.append(f"Missing claims: {missing}")

