    best_score = 0
    best_total = 8
    best_feedback = ""
    best_row = None

    # Check rows 4 and 5 as specified, but also be generous and check a wider range
    rows_to_check = set()
    for r in [4, 5]:
        if r <= ws.max_row:
            rows_to_check.add(r)
