            best_score = s
            best_total = t
            best_feedback = fb
            best_row = row_num

    if best_row is None:
        return {"pass": False, "score": 0.0, "feedback": "No valid rows found in the sheet."}

    ratio = best_score / best_total
    passed = best_score >= 8

    return {
