            return ""
        if isinstance(val, (datetime.datetime, datetime.date)):
            return val.strftime("%m/%d/%Y")
        s = str(val).strip()
        return s

    def values_match(cell_val, expected_val):
        n_cell = normalize(cell_val).lower()
        n_exp = expected_val.strip().lower()
        if n_cell == n_exp:
            return True
        # Handle date variations
        if n_exp == "04/24/2026":
            if n_cell in ["4/24/2026", "04/24/2026", "2026-04-24", "04-24-2026", "4-24-2026"]:
                return True
        # Handle minor whitespace/case differences
        if n_cell.replace(" ", "") == n_exp.replace(" ", ""):
            return True
        # Partial matching for things like "era processing"
        if n_exp in n_cell or n_cell in n_exp:
            if len(n_exp) > 3 and len(n_cell) > 3:
                return True
        return False

    def is_blank(val):
        if val is None:
            return True
        s = str(val).strip()
        return s == "" or s.lower() == "none"

    # Check rows 9, 10, 11 first, then expand search
    priority_rows = [9, 10, 11]
    check_rows = list(range(2, min(ws.max_row + 1, 50)))
    all_rows = priority_rows + [r for r in check_rows if r not in priority_rows]

    best_match_count = 0
    best_row_info = ""

    for row_num in all_rows:
        row_values = []
        for col in range(1, ws.max_column + 1):
            row_values.append(ws.cell(row=row_num, column=col).value)

        # Check RA ID
        ra_id_found = False
        for cv in row_values:
            nv = normalize(cv).lower().strip()
            if nv in valid_ra_ids:
                ra_id_found = True
                break

        # Check core required values
        core_matched = []
        for exp in core_required:
            found = False
            for cv in row_values:
                if values_match(cv, exp):
                    found = True
                    break
            core_matched.append(found)

        total_core = sum(core_matched) + (1 if ra_id_found else 0)
        if total_core > best_match_count:
            best_match_count = total_core
            best_row_info = f"Row {row_num}: {[normalize(v) for v in row_values]}"

        # Need RA ID + all core required values (6 total)
        if ra_id_found and all(core_matched):
            # Check status - rubric says "Resolved" and "04/24/2026" for last two,
            # but also says they could be "Open", BLANK instead
            has_resolved = False
            has_open = False
            status_val = "unknown"

            for cv in row_values:
                nv = normalize(cv).lower()
                if nv == "resolved":
                    has_resolved = True
                    status_val = "Resolved"
                if nv == "open":
                    has_open = True
                    status_val = "Open"

            # Status is acceptable if Resolved, Open, or blank (lenient)
            # Per rubric: last two cells could be "Open", BLANK instead of "Resolved", "04/24/2026"
            # We accept any of these combinations
            status_ok = True  # Be lenient per rubric

            row_display = [normalize(v) for v in row_values]
            return {
                "pass": True,
                "score": 1.0,
                "feedback": f"Row {row_num} contains all expected core values. RA ID found. Status={status_val}. Row contents: {row_display}"
            }

    # If not found, provide debugging info
    debug_info = []
    for row_num in priority_rows:
        row_values = []
        for col in range(1, ws.max_column + 1):
            row_values.append(normalize(ws.cell(row=row_num, column=col).value))
        debug_info.append(f"Row {row_num}: {row_values}")

    all_debug = []
    for row_num in range(1, min(ws.max_row + 1, 20)):
        row_values = []
        for col in range(1, ws.max_column + 1):
            row_values.append(normalize(ws.cell(row=row_num, column=col).value))
        all_debug.append(f"Row {row_num}: {row_values}")

    return {
        "pass": False,
        "score": 0.0,
        "feedback": f"No row contains all expected core values. Expected RA ID in {valid_ra_ids}, plus {core_required}. Best match had {best_match_count}/6 values in {best_row_info}. Rows 9-11 contents:\n" + "\n".join(debug_info) + "\n\nAll rows:\n" + "\n".join(all_debug)
    }

from pathlib import Path
import openpyxl
import re
from datetime import datetime


def normalize(val):
    """Normalize a cell value to a comparable string."""
    if val is None:
        return ""
    if isinstance(val, datetime):
        return val.strftime("%m/%d/%Y")
    s = str(val).strip()
    return s


def values_match(actual, expected):
    """Loosely compare two values."""
    a = normalize(actual)
    e = expected.strip()
    # Direct match (case-insensitive)
    if a.lower() == e.lower():
        return True
    # Try date parsing: expected is MM/DD/YYYY
    if '/' in e:
        try:
            exp_date = datetime.strptime(e, "%m/%d/%Y")
            # Try parsing actual in various formats
            for fmt in ["%m/%d/%Y", "%Y-%m-%d", "%m-%d-%Y", "%m/%d/%y", "%Y/%m/%d"]:
                try:
                    act_date = datetime.strptime(a, fmt)
                    if act_date.date() == exp_date.date():
                        return True
                except ValueError:
                    pass
        except ValueError:
            pass
    return False


def ra_id_match(actual):
    """Check if a cell value matches RA-2026-00{31,32,33}."""
    a = normalize(actual).upper()
    return a in ["RA-2026-0031", "RA-2026-0032", "RA-2026-0033"]


def verify(workspace_path, external_services_path=None):
    ws_path = Path(workspace_path)
    # Try case-insensitive search for file
    target_file = None
    for f in ws_path.iterdir():
        if f.name.lower() == "pbc_ra_queue.xlsx":
            target_file = f
            break

    if target_file is None:
        # Also try glob
        candidates = list(ws_path.glob("*RA_Queue*")) + list(ws_path.glob("*ra_queue*")) + list(ws_path.glob("*Ra_Queue*")) + list(ws_path.glob("*Queue*.xlsx"))
        if candidates:
            target_file = candidates[0]

    if target_file is None or not target_file.exists():
        return {"pass": False, "score": 0.0, "feedback": "File PBC_RA_Queue.xlsx not found in workspace."}

    try:
        wb = openpyxl.load_workbook(target_file, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open PBC_RA_Queue.xlsx: {e}"}

    ws = wb.active

    # The core required values (excluding RA ID which has special matching,
    # excluding priority which accepts any value,
    # and excluding status/completion date which are flexible)
    core_expected = [
        "04/24/2026",
        "CLM-2026-1105",
        "PAT-1058",
        "ERA Processing",
        "Maria Santos",
    ]

    # Search rows 8-12 to be generous (rubric says 9, 10, or 11)
    search_rows = list(range(8, 13))

    for row_num in search_rows:
        row_cells = []
        for col in range(1, ws.max_column + 1):
            cell_val = ws.cell(row=row_num, column=col).value
            row_cells.append(cell_val)

        # Check if RA ID matches
        ra_found = False
        for cell in row_cells:
            if ra_id_match(cell):
                ra_found = True
                break

        if not ra_found:
            continue

        # Check if all core expected values can be found in this row
        all_core_found = True
        matched_details = []
        matched_details.append("  RA ID found (one of RA-2026-0031/32/33)")

        for exp in core_expected:
            found = False
            for i, cell in enumerate(row_cells):
                if values_match(cell, exp):
                    found = True
                    matched_details.append(f"  Expected '{exp}' -> found '{normalize(cell)}' in column {i+1}")
                    break
            if not found:
                all_core_found = False
                matched_details.append(f"  Expected '{exp}' -> NOT FOUND")
                break

        if all_core_found:
            # Status can be "Resolved", "Open", or blank - check if present
            status_info = ""
            for i, cell in enumerate(row_cells):
                n = normalize(cell).lower()
                if n in ["resolved", "open"]:
                    status_info = f"Status='{normalize(cell)}' in column {i+1}"
                    break
            if not status_info:
                status_info = "Status is blank or not found (acceptable)"

            detail = "\n".join(matched_details)
            return {
                "pass": True,
                "score": 1.0,
                "feedback": f"All expected values found in row {row_num} of PBC_RA_Queue.xlsx:\n{detail}\n  {status_info}\nPriority: any value accepted."
            }

    # If not found, provide diagnostic info
    diag = []
    for row_num in search_rows:
        row_vals = []
        for col in range(1, ws.max_column + 1):
            v = ws.cell(row=row_num, column=col).value
            row_vals.append(normalize(v))
        diag.append(f"  Row {row_num}: {row_vals}")

    return {
        "pass": False,
        "score": 0.0,
        "feedback": f"Expected values not found in rows 8-12 of PBC_RA_Queue.xlsx.\nExpected RA ID: RA-2026-0031/32/33\nExpected core: {core_expected}\nStatus: 'Resolved', 'Open', or blank\nPriority: any value\nActual rows:\n" + "\n".join(diag)
    }

from pathlib import Path
import openpyxl
import re
from datetime import datetime

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "PBC_RA_Queue.xlsx"
    if not file_path.exists():
        # Try case-insensitive glob
        candidates = list(Path(workspace_path).glob("PBC_RA_Queue*")) + list(Path(workspace_path).glob("PBC_Ra_Queue*")) + list(Path(workspace_path).glob("pbc_ra_queue*"))
        if candidates:
            file_path = candidates[0]
        else:
            return {"pass": False, "score": 0.0, "feedback": "File PBC_RA_Queue.xlsx not found in workspace."}

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open PBC_RA_Queue.xlsx: {e}"}

    acceptable_ra_ids = ["RA-2026-0031", "RA-2026-0032", "RA-2026-0033"]

    # Expected fixed values (excluding RA ID, Date, and Priority which are handled separately)
    # The rubric says: RA ID, Date, CLM-2026-0967, PAT-1063, ERA Processing, [Any priority], Maria Santos, Open, BLANK
    expected_fixed = {
        "CLM": "CLM-2026-0967",
        "PAT": "PAT-1063",
        "TYPE": "ERA Processing",
        "ASSIGNEE": "Maria Santos",
        "STATUS": "Open"
    }

    def normalize(val):
        if val is None:
            return ""
        if isinstance(val, datetime):
            return val.strftime("%m/%d/%Y")
        s = str(val).strip()
        return s

    def clean(s):
        return s.lower().replace(" ", "").replace("-", "").replace("/", "").replace("_", "")

    def match_date(actual):
        a_clean = normalize(actual)
        # Try multiple date formats
        try:
            for fmt in ["%m/%d/%Y", "%Y-%m-%d", "%m-%d-%Y", "%d/%m/%Y", "%B %d, %Y", "%m/%d/%y"]:
                try:
                    parsed = datetime.strptime(a_clean, fmt)
                    if parsed.month == 4 and parsed.day == 24 and parsed.year == 2026:
                        return True
                except:
                    pass
        except:
            pass
        # Fallback: clean comparison
        if clean(a_clean) == clean("04/24/2026"):
            return True
        if clean(a_clean) == "04242026":
            return True
        return False

    def match_ra_id(actual):
        a = normalize(actual)
        if not a:
            return False
        for rid in acceptable_ra_ids:
            if clean(a) == clean(rid):
                return True
            if a.upper().replace("-", "").replace(" ", "") == rid.upper().replace("-", ""):
                return True
        # Regex: RA-2026-003[1-3] with flexible separators
        pattern = r'(?i)ra[\-_ ]?2026[\-_ ]?0{0,2}3[123]'
        if re.search(pattern, a):
            return True
        return False

    def fuzzy_match(expected, actual):
        e_norm = normalize(expected)
        a_norm = normalize(actual)
        if not a_norm and not e_norm:
            return True
        if clean(e_norm) == clean(a_norm):
            return True
        if e_norm.lower().strip() == a_norm.lower().strip():
            return True
        return False

    def check_row(row_values):
        """Check if a row contains all expected values. Returns (True, msg) or (False, msg)."""
        # Strategy 1: Ordered match
        # Expected column order: A=RA_ID, B=Date, C=CLM, D=PAT, E=Type, F=Priority, G=Assignee, H=Status, I=blank(notes)
        if len(row_values) >= 8:
            ordered_ok = True
            issues = []
            # Column A (index 0): RA ID
            if not match_ra_id(row_values[0]):
                ordered_ok = False
                issues.append(f"Col A: expected RA-2026-003[1-3], got '{normalize(row_values[0])}'")
            # Column B (index 1): Date
            if ordered_ok and not match_date(row_values[1]):
                ordered_ok = False
                issues.append(f"Col B: expected 04/24/2026, got '{normalize(row_values[1])}'")
            # Column C (index 2): CLM-2026-0967
            if ordered_ok and not fuzzy_match("CLM-2026-0967", row_values[2]):
                ordered_ok = False
                issues.append(f"Col C: expected CLM-2026-0967, got '{normalize(row_values[2])}'")
            # Column D (index 3): PAT-1063
            if ordered_ok and not fuzzy_match("PAT-1063", row_values[3]):
                ordered_ok = False
                issues.append(f"Col D: expected PAT-1063, got '{normalize(row_values[3])}'")
            # Column E (index 4): ERA Processing
            if ordered_ok and not fuzzy_match("ERA Processing", row_values[4]):
                ordered_ok = False
                issues.append(f"Col E: expected ERA Processing, got '{normalize(row_values[4])}'")
            # Column F (index 5): Priority - ANY value is acceptable per rubric
            # No check needed
            # Column G (index 6): Maria Santos
            if ordered_ok and not fuzzy_match("Maria Santos", row_values[6]):
                ordered_ok = False
                issues.append(f"Col G: expected Maria Santos, got '{normalize(row_values[6])}'")
            # Column H (index 7): Open
            if ordered_ok and not fuzzy_match("Open", row_values[7]):
                ordered_ok = False
                issues.append(f"Col H: expected Open, got '{normalize(row_values[7])}'")
            # Column I (index 8): blank
            if ordered_ok:
                col9_val = row_values[8] if len(row_values) > 8 else None
                if col9_val is None or str(col9_val).strip() == "":
                    return True, "ordered match with blank column 9"
                else:
                    ordered_ok = False
                    issues.append(f"Col I: expected BLANK, got '{normalize(col9_val)}'")

        # Strategy 2: Unordered match - find all values somewhere in the row
        found_ra = False
        for rv in row_values:
            if match_ra_id(rv):
                found_ra = True
                break

        found_date = False
        for rv in row_values:
            if match_date(rv):
                found_date = True
                break

        found_others = True
        missing = []
        for key, exp in expected_fixed.items():
            found = False
            for rv in row_values:
                if fuzzy_match(exp, rv):
                    found = True
                    break
            if not found:
                found_others = False
                missing.append(exp)

        has_blank = any(v is None or str(v).strip() == "" for v in row_values)

        if found_ra and found_date and found_others and has_blank:
            return True, "unordered match"

        details = []
        if not found_ra:
            details.append("RA ID not found (expected one of RA-2026-0031/0032/0033)")
        if not found_date:
            details.append("Date 04/24/2026 not found")
        if missing:
            details.append(f"Missing values: {missing}")
        if not has_blank:
            details.append("No blank cell found")
        return False, "; ".join(details)

    # Check rows 9, 10, 11
    for row_num in [9, 10, 11]:
        row_values = []
        for col in range(1, max(ws.max_column + 1, 15)):
            cell_val = ws.cell(row=row_num, column=col).value
            row_values.append(cell_val)

        ok, msg = check_row(row_values)
        if ok:
            wb.close()
            row_display = [normalize(v) for v in row_values[:min(len(row_values), 12)]]
            return {"pass": True, "score": 1.0, "feedback": f"Row {row_num} contains all expected values ({msg}): {row_display}"}

    # Diagnostic info
    diag = []
    for row_num in [9, 10, 11]:
        row_values = []
        for col in range(1, min(ws.max_column + 1, 15)):
            cell_val = ws.cell(row=row_num, column=col).value
            row_values.append(normalize(cell_val))
        raw_values = [ws.cell(row=row_num, column=c).value for c in range(1, max(ws.max_column + 1, 15))]
        ok, msg = check_row(raw_values)
        diag.append(f"Row {row_num}: {row_values} -- Issues: {msg}")

    wb.close()
    return {"pass": False, "score": 0.0, "feedback": f"No matching row found in rows 9-11 of PBC_RA_Queue.xlsx. Expected: RA-2026-003[1-3], 04/24/2026, CLM-2026-0967, PAT-1063, ERA Processing, [Any Priority], Maria Santos, Open, BLANK. Actual rows:\n" + "\n".join(diag)}

from pathlib import Path
import openpyxl


def verify(workspace_path, external_services_path=None):
    target = Path(workspace_path) / "PBC_RA_Queue.xlsx"
    # Also try case-insensitive search
    if not target.exists():
        candidates = list(Path(workspace_path).glob("*"))
        for c in candidates:
            if c.name.lower() == "pbc_ra_queue.xlsx":
                target = c
                break

    if not target.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File PBC_RA_Queue.xlsx not found in workspace. Files present: {[f.name for f in Path(workspace_path).iterdir()]}"}

    try:
        wb = openpyxl.load_workbook(target, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open PBC_RA_Queue.xlsx: {e}"}

    ws = wb.active

    rows = []
    for row in ws.iter_rows(min_row=1, values_only=True):
        normalized = []
        for cell in row:
            if isinstance(cell, str):
                normalized.append(cell.strip().lower())
            elif cell is None:
                normalized.append(None)
            else:
                normalized.append(cell)
        rows.append(tuple(normalized))

    if len(rows) <= 1:
        return {"pass": True, "score": 1.0, "feedback": f"PBC_RA_Queue.xlsx has {len(rows)} row(s); no duplicates possible."}

    header = rows[0]
    data_rows = rows[1:]

    # Filter out completely empty rows
    data_rows = [r for r in data_rows if any(c is not None for c in r)]

    issues = []

    # Check 1: Duplicate entire rows
    seen_rows = set()
    dup_rows = []
    for i, r in enumerate(data_rows):
        if r in seen_rows:
            dup_rows.append((i + 2, r))  # +2 for 1-indexed + header
        else:
            seen_rows.add(r)

    if dup_rows:
        dup_info = "; ".join([f"Row {idx}" for idx, vals in dup_rows[:5]])
        issues.append(f"Found {len(dup_rows)} duplicate row(s). Examples: {dup_info}")

    # Check 2: Duplicate Queue Entry IDs
    # Try to find a column that looks like a Queue Entry ID
    qe_col_idx = None
    if header:
        for idx, h in enumerate(header):
            if h is not None and isinstance(h, str):
                h_lower = h.lower().strip()
                if 'queue entry id' in h_lower or 'queueentryid' in h_lower or 'queue_entry_id' in h_lower or h_lower == 'id' or 'entry id' in h_lower:
                    qe_col_idx = idx
                    break
        # If not found, also check for columns starting with 'queue'
        if qe_col_idx is None:
            for idx, h in enumerate(header):
                if h is not None and isinstance(h, str):
                    h_lower = h.lower().strip()
                    if 'queue' in h_lower and 'id' in h_lower:
                        qe_col_idx = idx
                        break

    if qe_col_idx is not None:
        seen_ids = {}
        dup_ids = []
        for i, r in enumerate(data_rows):
            if qe_col_idx < len(r):
                val = r[qe_col_idx]
                if val is not None:
                    val_key = str(val).strip().lower()
                    if val_key in seen_ids:
                        dup_ids.append((i + 2, val))
                    else:
                        seen_ids[val_key] = i + 2
        if dup_ids:
            dup_id_info = "; ".join([f"Row {idx}: ID={val}" for idx, val in dup_ids[:5]])
            issues.append(f"Found {len(dup_ids)} duplicate Queue Entry ID(s). Examples: {dup_id_info}")

    if issues:
        return {"pass": False, "score": 0.0, "feedback": "PBC_RA_Queue.xlsx has duplicates: " + " | ".join(issues)}
    else:
        id_note = f" Queue Entry ID column found at index {qe_col_idx}, all unique." if qe_col_idx is not None else " No Queue Entry ID column identified; only checked full row uniqueness."
        return {"pass": True, "score": 1.0, "feedback": f"PBC_RA_Queue.xlsx has {len(data_rows)} data rows with no duplicate rows or Queue Entry IDs.{id_note}"}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # This rubric checks external services (Slack data)
    # Try multiple possible locations for slack_data.json
    slack_path = None
    candidates = []

    if external_services_path:
        candidates.append(Path(external_services_path) / "slack_data.json")

    # Also check workspace-based paths
    wp = Path(workspace_path)
    candidates.append(wp / "external_data" / "final" / "slack_data.json")
    candidates.append(wp / "slack_data.json")

    for c in candidates:
        if c.exists():
            slack_path = c
            break

    if slack_path is None:
        return {"pass": False, "score": 0.0, "feedback": f"Could not find slack_data.json. Checked: {[str(c) for c in candidates]}"}

    try:
        with open(slack_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse slack_data.json: {e}"}

    messages = data.get("messages", {})

    # Find the general channel and rcm-team channel
    # First, map channel names to IDs from channels info
    channels = data.get("channels", {})
    general_id = None
    rcm_id = None
    for ch_id, ch_info in channels.items():
        name = ch_info.get("name", "").lower()
        if name == "general":
            general_id = ch_id
        elif name == "rcm-team":
            rcm_id = ch_id

    # Count messages
    general_msgs = []
    rcm_msgs = []

    # Try by channel ID first, then by channel name as key
    for key, msg_list in messages.items():
        if key == general_id or key.lower() == "general":
            general_msgs = msg_list
        elif key == rcm_id or key.lower() == "rcm-team":
            rcm_msgs = msg_list

    general_count = len(general_msgs)
    rcm_count = len(rcm_msgs)

    feedback_parts = []
    passed = True
    score = 0.0

    if general_count == 3:
        feedback_parts.append(f"#general has {general_count} messages (expected 3). PASS.")
        score += 0.5
    else:
        feedback_parts.append(f"#general has {general_count} messages (expected 3). FAIL.")
        passed = False

    if rcm_count == 8:
        feedback_parts.append(f"#rcm-team has {rcm_count} messages (expected 8). PASS.")
        score += 0.5
    else:
        feedback_parts.append(f"#rcm-team has {rcm_count} messages (expected 8). FAIL.")
        passed = False

    return {"pass": passed, "score": score, "feedback": " | ".join(feedback_parts)}
